import React, { useEffect, useRef, useState } from 'react';
import { api } from '../contexts/AuthContext';

const VideoPlayer = ({ videoId, src, isAuthenticated, duration }) => {
  const videoRef = useRef(null);
  const [initialTime, setInitialTime] = useState(0);
  const progressIntervalRef = useRef(null);
  const lastReportedTimeRef = useRef(0);

  // Load saved progress on mount
  useEffect(() => {
    const loadProgress = async () => {
      if (!isAuthenticated || !videoId) return;

      try {
        const response = await api.get(`/video/watch-history/${videoId}/progress`);
        if (response.data.progress > 0 && response.data.progress < 95) {
          setInitialTime(response.data.watch_duration);
        }
      } catch (err) {
        console.error('Error loading watch progress:', err);
      }
    };

    loadProgress();
  }, [videoId, isAuthenticated]);

  // Set initial time when video metadata is loaded
  const handleLoadedMetadata = () => {
    if (videoRef.current && initialTime > 0) {
      videoRef.current.currentTime = initialTime;
    }
  };

  // Report progress periodically
  const startProgressTracking = () => {
    if (!isAuthenticated || progressIntervalRef.current) return;

    progressIntervalRef.current = setInterval(() => {
      if (videoRef.current) {
        const currentTime = videoRef.current.currentTime;
        const totalDuration = videoRef.current.duration || duration;

        // Only report if time has changed significantly (more than 5 seconds)
        if (Math.abs(currentTime - lastReportedTimeRef.current) >= 5) {
          const progress = totalDuration > 0 ? (currentTime / totalDuration) * 100 : 0;

          reportProgress(currentTime, totalDuration, progress);
          lastReportedTimeRef.current = currentTime;
        }
      }
    }, 5000); // Report every 5 seconds
  };

  const stopProgressTracking = () => {
    if (progressIntervalRef.current) {
      clearInterval(progressIntervalRef.current);
      progressIntervalRef.current = null;
    }
  };

  const reportProgress = async (currentTime, totalDuration, progress) => {
    if (!isAuthenticated || !videoId) return;

    try {
      await api.post(`/video/watch-history/${videoId}`, {
        watch_duration: Math.floor(currentTime),
        total_duration: Math.floor(totalDuration),
        progress: Math.min(progress, 100)
      });
    } catch (err) {
      console.error('Error reporting watch progress:', err);
    }
  };

  const handlePlay = () => {
    startProgressTracking();
  };

  const handlePause = () => {
    stopProgressTracking();
    // Report final progress on pause
    if (videoRef.current) {
      const currentTime = videoRef.current.currentTime;
      const totalDuration = videoRef.current.duration || duration;
      const progress = totalDuration > 0 ? (currentTime / totalDuration) * 100 : 0;
      reportProgress(currentTime, totalDuration, progress);
    }
  };

  const handleEnded = () => {
    stopProgressTracking();
    // Mark as 100% complete when ended
    if (isAuthenticated && videoId) {
      reportProgress(duration || 0, duration || 0, 100);
    }
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopProgressTracking();
    };
  }, []);

  return (
    <video
      ref={videoRef}
      controls
      autoPlay
      className="w-full h-full"
      src={src}
      onLoadedMetadata={handleLoadedMetadata}
      onPlay={handlePlay}
      onPause={handlePause}
      onEnded={handleEnded}
    >
      您的浏览器不支持视频播放。
    </video>
  );
};

export default VideoPlayer;
